export function Decocube(x, y, z, scale = 1.5, shape = 0.9, thickness = 0.15) {
    x *= scale;
    y *= scale;
    z *= scale;

	return	( (x*x+y*y-shape)**2 + (z*z-1)**2 ) *
			( (y*y+z*z-shape)**2 + (x*x-1)**2 ) *
			( (z*z+x*x-shape)**2 + (y*y-1)**2 ) - thickness;
};



export function Tooth (x, y, z, scale = 1.2, thickness = 0.95) {
    x *= scale;
    y *= scale;
    z *= scale;

	return ((2 * (x**4 + y**4 + z**4)) - (2 * (x**2 + y**2 + z**2))) + thickness;
};

export function LumpySphere(x, y, z, scale = 1.2, lumpiness = 0.25, frequency = 10) {
    x *= scale;
    y *= scale;
    z *= scale;

    let r2 = x**2 + y**2 + z**2;
    return	r2 - 1.0 + lumpiness *
    		Math.sin(frequency * x) *
    		Math.sin(frequency * y) *
    		Math.sin(frequency * z);
}

function smoothUnion(a, b, k) {
    return -Math.log(Math.exp(-k*a) + Math.exp(-k*b)) / k;
}

export function supersphere242(x, y, z) {
    return x**2 + y**4 + z**2 - 0.3;
}

export function CushionCluster(x, y, z, scale = 1.3) {
    x *= scale;
    y *= scale;
    z *= scale;

    let d = supersphere242(x, y*1.5, z);
    
    for (let i = 0; i < 8; i++) {
        let angle = (i / 8) * Math.PI * 2;
        let ox = Math.cos(angle) * 0.9;
        let oz = Math.sin(angle) * 0.9;
        
        let sub = supersphere242((x-ox)*1.5, y*1.5, (z - oz)*1.5);
        d = smoothUnion(d, sub, 12);
    }
    
    return d;
}

export function TorusXY(x, y, z, R = 0.7, r = 0.2) {
    // R = major radius (center to tube center)
    // r = minor radius (tube radius / thickness)
    const q = Math.sqrt(x**2 + y**2) - R;
    return Math.sqrt(q**2 + z**2) - r;
}

export function TorusXZ(x, y, z, R = 0.7, r = 0.2) {
    // R = major radius (center to tube center)
    // r = minor radius (tube radius / thickness)
    const q = Math.sqrt(x**2 + z**2) - R;
    return Math.sqrt(q**2 + y**2) - r;
}

export function TorusYZ(x, y, z, R = 0.7, r = 0.2) {
    // R = major radius (center to tube center)
    // r = minor radius (tube radius / thickness)
    const q = Math.sqrt(y**2 + z**2) - R;
    return Math.sqrt(q**2 + x**2) - r;
}

export function SuperSphere(x, y, z, scale = 1, power = 3) {
	x *= scale;
	y *= scale;
	z *= scale;
	
	return (x**2)**power + (y**2)**power + (z**2)**power - 0.3;
}

export function SuperSphereCluster(x, y, z, scale = 1.75, power = 3) {
	x *= scale;
	y *= scale;
	z *= scale;
	
    const k = 5;  // smoothness
    const x4 = x*x*x*x;
    const y4 = y*y*y*y;
    const z4 = z*z*z*z;
    
    let field = x4 + y4 + z4 - 1.5;
    
    let nx = x - 1;
    let ssfield = (nx*nx*nx*nx) + y4 + z4 - 0.3;
    field = smoothUnion(field, ssfield, k);
    
    nx = x + 1;
    ssfield = (nx*nx*nx*nx) + y4 + z4 - 0.3;
    field = smoothUnion(field, ssfield, k);

    let ny = y - 1;
    ssfield = x4 + (ny*ny*ny*ny) + z4 - 0.3;
    field = smoothUnion(field, ssfield, k);

    ny = y + 1;
    ssfield = x4 + (ny*ny*ny*ny) + z4 - 0.3;
    field = smoothUnion(field, ssfield, k);
    
    let nz = z - 1;
    ssfield = x4 + y4 + (nz*nz*nz*nz) - 0.3;
    field = smoothUnion(field, ssfield, k);

    nz = z + 1;
    ssfield = x4 + y4 + (nz*nz*nz*nz) - 0.3;
    field = smoothUnion(field, ssfield, k);

    return field;
}

export function GumdropTorus(x, y, z) {
	x *= 2.2;
	y *= 2.2;
	z *= 2.2;

    return (
        4 * x**4 +
        4 * y**4 +
        8 * y**2 * z**2 +
        4 * z**4 +
        17 * x**2 * y**2 +
        17 * x**2 * z**2 -
        20 * x**2 -
        20 * y**2 -
        20 * z**2 +
        17
    );
}

export function BasicBlobs(x, y, z) {

    const scale = 1.3;
    x *= scale;
    y *= scale;
    z *= scale;

    const blobCount = 8;
    const ringRadius = 1;
    const sharpness = 7;
    const twoPi = Math.PI * 2;

    let field = 0;

    for (let i = 0; i < blobCount; i++) {

        const angle = (i / blobCount) * twoPi;

        // Ring in XZ plane (spread along Y axis)
        const cx = Math.cos(angle) * ringRadius;
        const cy = 0;
        const cz = Math.sin(angle) * ringRadius;

        const dx = x - cx;
        const dy = y - cy;
        const dz = z - cz;

        field += Math.exp(-sharpness * (dx*dx + dy*dy + dz*dz));
    }

    // central blob
    const dx = x * 0.7;
    const dz = z * 0.7;
    const dy = y * 0.9;

    field += Math.exp(-sharpness * (dx*dx + dy*dy + dz*dz));

    return field - 0.6;
}

export function WavePattern(x, y, z) {
    let sx = x * 12;
    let sy = y * 16;
    let sz = z * 12;
	
	const surface_top =	Math.cos(sx) * Math.cos(sz) +
			Math.cos((Math.sqrt(3)*sx-sz)/2) * Math.cos((sx + Math.sqrt(3) * sz)/2) +
			Math.cos((Math.sqrt(3)*sx+sz)/2) * Math.cos((sx - Math.sqrt(3) * sz)/2) + sy + 4;

	const surface_bottom =	Math.cos(sx) * Math.cos(sz) +
			Math.cos((Math.sqrt(3)*sx-sz)/2) * Math.cos((sx + Math.sqrt(3) * sz)/2) +
			Math.cos((Math.sqrt(3)*sx+sz)/2) * Math.cos((sx - Math.sqrt(3) * sz)/2) + sy - 4;
			
    const radius = 1;
    const by = y * 3;
    const dist = x**2 + by**2 + z**2;
    const sphereBound = dist - radius;

    return smoothMax(surface_top * surface_bottom, sphereBound, 20);
}

export function SquashedWavePattern(x, y, z, scale = 12, flatness = 2.0) {
    x *= scale;
    y *= scale;
    z *= scale;
	
    // 1. Calculate the raw interference pattern
    let wave = Math.cos(x) * Math.cos(z) +
               Math.cos((Math.sqrt(3) * x - z) / 2) * Math.cos((x + Math.sqrt(3) * z) / 2) +
               Math.cos((Math.sqrt(3) * x + z) / 2) * Math.cos((x - Math.sqrt(3) * z) / 2);

    // 2. Apply the "squash" (Hyperbolic Tangent)
    // We divide by the flatness after tanh to keep the scale consistent
    let squashedWave = Math.tanh(wave * flatness) / flatness;

    // 3. Combine with your vertical offset
    return (squashedWave + y);
}

export function Tetrahedral(x, y, z) {
    x *= 3.1;
    y *= 3.1;
    z *= 3.1;

    return (
        x**4 +
        2 * x**2 * y**2 +
        2 * x**2 * z**2 +
        y**4 +
        2 * y**2 * z**2 +
        z**4 +
        8 * x * y * z -
        10.2 * x**2 -
        10.2 * y**2 -
        10.2 * z**2 +
        25
    );
}

function smoothMin(a, b, k) {
    const h = Math.max(k - Math.abs(a - b), 0.0) / k;
    return Math.min(a, b) - h * h * h * k * (1.0/6.0);
}

export function ThreeTori(x, y, z, scale = 3.7, major_radius = 3, tube_radius = 0.6, blend_factor = 0.3) {
    x *= scale;
    y *= scale;
    z *= scale;

    // Six tori (positive & negative directions implicitly covered)
    const f1 = TorusXY(x, y, z, major_radius, tube_radius);
    const f2 = TorusXZ(x, y, z, major_radius, tube_radius);
    const f3 = TorusYZ(x, y, z, major_radius, tube_radius);

    let field = smoothMin(f1, f2, blend_factor);
    field = smoothMin(field, f3, blend_factor);

    return field;
}

export function TwistedWaveTorus(x, y, z) {
    x *= 2.3;
    y *= 2.3;
    z *= 2.3;

    const R = 1.5;      // major radius
    const r = 0.6;      // base tube radius
    const A = 0.06;      // wave amplitude
    const n = 6.0;      // waves around tube
    const m = 3.0;      // twist factor

    // Distance from Y axis
    let radial = Math.sqrt(x*x + z*z);

    // Angle around torus ring
    let theta = Math.atan2(z, x);

    // Local tube coordinates
    let dx = radial - R;
    let phi = Math.atan2(y, dx);

    // Twisted wave modulation
	let wave = A * Math.sin(n * phi + m * theta) + 0.1 * Math.cos(2.0 * theta);

    // Final implicit field
    return dx*dx + y*y - (r + wave)*(r + wave);
}


function AlgebraicSurface(x, y, z, scale = 4.0) {

    x *= scale;
    y *= scale;
    z *= scale;

    const x2 = x * x;
    const y2 = y * y;
    const z2 = z * z;

    const term1 = (x2 - 4) * (x2 - 4);
    const term2 = (y2 - 4) * (y2 - 4);
    const term3 = (z2 - 4) * (z2 - 4);

    const mixedQuartic =
        3 * (x2 * y2 + x2 * z2 + y2 * z2);

    const tripleProduct =
        6 * x * y * z;

    const quadratic =
        -10 * (x2 + y2 + z2);

    return (
        term1 +
        term2 +
        term3 +
        mixedQuartic +
        tripleProduct +
        quadratic +
        22
    );
}

export function SineRippleSphere(
    x, y, z,
    scale = 2,
    frequency = 4,
    amplitude = 1
) {
    x *= scale;
    y *= scale;
    z *= scale;

    const r2 = x*x + y*y + z*z;

    const ripples =
        amplitude * (
            Math.sin(frequency * x) +
            Math.sin(frequency * y) +
            Math.sin(frequency * z)
        );

    return r2 + ripples - 1;
}

function smoothMax(a, b, k) {
    const h = Math.max(k - Math.abs(a - b), 0.0) / k;
    return Math.max(a, b) + h*h*h * k * (1/6);
}

export function CoredTwistedRipple(
    x, y, z,
    scale = 1.2,
    baseRadius = 1,
    radialFreq = 6,
    angularFreq = 5,
    amplitude = 0.25,
    twistAmount = 0.8,
    cylinderRadius = 0.3,
    smoothness = 1
) {
    x *= scale;
    y *= scale;
    z *= scale;

    const r = Math.sqrt(x*x + y*y + z*z);
    const theta = Math.atan2(y, x);

    const twistedTheta = theta + twistAmount * z;

    const radialWave = Math.sin(radialFreq * r);
    const angularWave = Math.sin(angularFreq * twistedTheta);

    const displacement =
        amplitude * radialWave * angularWave;

    // Main surface
    const surface =
        r*r - (baseRadius + displacement) ** 2;

    // Cylinder along Z axis
    const cylinder =
        x*x + y*y - cylinderRadius * cylinderRadius;

    // Smooth subtraction (remove cylinder)
    return smoothMax(surface, -cylinder, smoothness);
}

export function PolyhedralSuperSphere(x, y, z, scale = 1) {
    const n = 8;         // exponent
    const r = 1.1;       // radius
    const a = 0.4;       // diagonal influence
    
    x *= scale;
    y *= scale;
    z *= scale;

    const axis =
        Math.pow(Math.abs(x), n) +
        Math.pow(Math.abs(y), n) +
        Math.pow(Math.abs(z), n);

    const diag =
        Math.pow(Math.abs(x + y + z), n) +
        Math.pow(Math.abs(x + y - z), n) +
        Math.pow(Math.abs(x - y + z), n) +
        Math.pow(Math.abs(-x + y + z), n);

    return axis + a * diag - Math.pow(r, n);
}

export function PolyCubeBlend(x, y, z, scale = 1.1) {

    const n = 8;
    const pn = 8;
    const r = 1.1;
    const a = 0.4;

    x *= scale;
    y *= scale;
    z *= scale;

    // --- polyhedral supersphere ---
    const axis =
        Math.pow(Math.abs(x), pn) +
        Math.pow(Math.abs(y), pn) +
        Math.pow(Math.abs(z), pn);

    const diag =
        Math.pow(Math.abs(x + y + z), pn) +
        Math.pow(Math.abs(x + y - z), pn) +
        Math.pow(Math.abs(x - y + z), pn) +
        Math.pow(Math.abs(-x + y + z), pn);

    const poly = axis + a * diag - Math.pow(r, pn);

    // --- cube supersphere ---
    const cube =
        Math.pow(Math.abs(x), n) +
        Math.pow(Math.abs(y), n) +
        Math.pow(Math.abs(z), n) -
        Math.pow(r * 0.67, n);

    // --- smooth union ---
    return smoothUnion(poly, cube, 0.5);
}

function buildGeodesicPoints(count) {

    const points = [];
    const goldenAngle = Math.PI * (3 - Math.sqrt(5));

    for (let i = 1; i < count - 1; i++) {

        const y = 1 - (i / (count - 1)) * 2;
        const r = Math.sqrt(1 - y*y);

        const theta = goldenAngle * i;

        points.push({
            x: Math.cos(theta) * r,
            y: y,
            z: Math.sin(theta) * r
        });
    }

    return points;
}

const dents = buildGeodesicPoints(30);

export function GeodesicPointsSphere(x, y, z, scale = 1.5) {

    x *= scale;
    y *= scale;
    z *= scale;

    const R = 1.0;
    const dentDepth = 0.5;
    const dentSharpness = 50;

    const r = Math.sqrt(x*x + y*y + z*z) + 1e-6;

    const dx = x / r;
    const dy = y / r;
    const dz = z / r;

    let dentField = 0;

    for (let i = 0; i < dents.length; i++) {

        const p = dents[i];

        const dot = dx*p.x + dy*p.y + dz*p.z;

		// Add for dents, subtract for spikes
        dentField -= Math.exp(dentSharpness * (dot - 1));
    }

    const surfaceRadius = R - dentDepth * dentField;

    return r - surfaceRadius;
}

/**
 * Chair Surface Field Function
 * @param {number} x, y, z - Coordinates
 * @param {object} params - Surface parameters (k, a, b)
 * @returns {number} The field value (Surface exists at result === 0)
 */
export function chairSurfaceField(x, y, z, params = { k: 1, a: 0.94, b: 0.8 }) {
    const { k, a, b } = params;

    // First part: (x^2 + y^2 + z^2 - a * k^2)^2
    const sphereTerm = Math.pow(x * x + y * y + z * z - a * k * k, 2);

    // Second part: b * [(z - k)^2 - 2x^2] * [(z + k)^2 - 2y^2]
    const chairTerm = b * (Math.pow(z - k, 2) - 2 * x * x) * (Math.pow(z + k, 2) - 2 * y * y);

    return sphereTerm - chairTerm;
}

export function PiriformDiabolo(x, y, z, scale = 3.5, a = 2, b = 1) {

    x *= scale;
    y *= scale;
    z *= scale;

	const angle = Math.atan2(z, y)
	const r = Math.sqrt(y*y + z*z)
	const r2 = r * (1 + 0.08 * Math.sin(4 * angle + 3 * x))
	const yz = r2 * r2;
	
	//const yz = y * y + z * z;
    const a4 = a * a * a * a;

    let x1 = x + 0.5;
    let surface1 = (a4 * yz) - (b * 2 * x1 * x1 * x1 * (2 * a - x1));

    let x2 = -(x - 0.5);
    let surface2 = (a4 * yz) - (b * 2 * x2 * x2 * x2 * (2 * a - x2));

    return smoothUnion(surface1, surface2, 0.1);
}

let currentFieldIndex = 0;

export function incrementFieldFunction() {
	currentFieldIndex = (currentFieldIndex + 1) % fieldFunctions.length;
}

export function decrementFieldFunction() {
	currentFieldIndex--;
	if (currentFieldIndex < 0) {
		currentFieldIndex = fieldFunctions.length - 1;
	}
}

export function getCurrentField() {
    return fieldFunctions[currentFieldIndex].fn;
}

export function getFieldFunctionName() {
    return fieldFunctions[currentFieldIndex].name;
}

